"use client"

import { useState, useEffect } from "react"
import { useParams, useRouter, useSearchParams } from "next/navigation"
import Link from "next/link"
import { useAuth } from "@/lib/auth-context"
import { formatCurrency } from "@/lib/networks"
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import { Label } from "@/components/ui/label"
import { Separator } from "@/components/ui/separator"
import { toast } from "sonner"
import { motion } from "framer-motion"
import {
  ArrowLeft,
  Phone,
  Clock,
  Calendar,
  CreditCard,
  Loader2,
  CheckCircle2,
  Copy,
  MessageSquare,
  AlertCircle,
} from "lucide-react"

const rentalDurations = [
  { hours: 1, label: "1 hour", multiplier: 0.1 },
  { hours: 6, label: "6 hours", multiplier: 0.3 },
  { hours: 12, label: "12 hours", multiplier: 0.5 },
  { hours: 24, label: "24 hours", multiplier: 1 },
  { hours: 72, label: "3 days", multiplier: 2.5 },
  { hours: 168, label: "7 days", multiplier: 5 },
]

interface Service {
  id: string
  name: string
  category: string
  description: string
  base_cost: number
  markup_percentage: number
  rental_multiplier: number
  onetime_price: number
  rental_price_per_day: number
}

interface ActiveNumber {
  id: string
  number: string
  service_name: string
  type: "onetime" | "rental"
  status: string
  time_remaining_ms: number
  time_remaining_formatted: string
  is_expired: boolean
  sms_count: number
  expires_at: string
}

interface SMS {
  id: string
  from_number: string
  message: string
  received_at: string
}

export default function ServiceDetailPage() {
  const params = useParams()
  const router = useRouter()
  const searchParams = useSearchParams()
  const viewNumberId = searchParams.get("view")
  const { user, refreshUser } = useAuth()
  
  const serviceId = params.serviceId as string
  
  const [loading, setLoading] = useState(true)
  const [service, setService] = useState<Service | null>(null)
  const [purchaseType, setPurchaseType] = useState<"onetime" | "rental">("onetime")
  const [rentalDuration, setRentalDuration] = useState(24)
  const [activeNumber, setActiveNumber] = useState<ActiveNumber | null>(null)
  const [smsList, setSmsList] = useState<SMS[]>([])
  const [isPurchasing, setIsPurchasing] = useState(false)
  const [pollingInterval, setPollingInterval] = useState<NodeJS.Timeout | null>(null)

  useEffect(() => {
    fetchService()
    if (viewNumberId) {
      fetchNumberDetails(viewNumberId)
    }
    
    return () => {
      if (pollingInterval) clearInterval(pollingInterval)
    }
  }, [serviceId, viewNumberId])

  const fetchService = async () => {
    try {
      const response = await fetch("/api/verification/services")
      const data = await response.json()
      
      if (data.success) {
        const found = data.data.services.find((s: Service) => s.id === serviceId)
        if (found) {
          setService(found)
        }
      }
    } catch (err) {
      console.error("Failed to fetch service:", err)
    } finally {
      setLoading(false)
    }
  }

  const fetchNumberDetails = async (numberId: string) => {
    try {
      // Fetch number details
      const response = await fetch("/api/verification/numbers?include_expired=true")
      const data = await response.json()
      
      if (data.success) {
        const found = data.data.numbers.find((n: ActiveNumber) => n.id === numberId)
        if (found) {
          setActiveNumber(found)
          fetchSMS(numberId)
          
          // Start polling for SMS if active
          if (found.status === "active" && !found.is_expired) {
            const interval = setInterval(() => fetchSMS(numberId), 5000)
            setPollingInterval(interval)
          }
        }
      }
    } catch (err) {
      console.error("Failed to fetch number details:", err)
    }
  }

  const fetchSMS = async (numberId: string) => {
    try {
      const response = await fetch(`/api/verification/sms/${numberId}`)
      const data = await response.json()
      
      if (data.success) {
        setSmsList(data.data.sms)
      }
    } catch (err) {
      console.error("Failed to fetch SMS:", err)
    }
  }

  const calculatePrice = () => {
    if (!service) return 0
    
    if (purchaseType === "onetime") {
      return service.onetime_price
    }
    
    const duration = rentalDurations.find(d => d.hours === rentalDuration)
    return service.rental_price_per_day * (duration?.multiplier || 1)
  }

  const handlePurchase = async () => {
    if (!service) return
    
    setIsPurchasing(true)
    try {
      const response = await fetch("/api/verification/purchase", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          serviceId: service.id,
          type: purchaseType,
          durationHours: purchaseType === "rental" ? rentalDuration : undefined,
        }),
      })
      
      const data = await response.json()
      
      if (data.success) {
        toast.success(`${purchaseType === "rental" ? "Rental" : "Number"} purchased successfully!`)
        refreshUser()
        
        // Set the active number and start viewing
        setActiveNumber({
          id: data.data.number_id,
          number: data.data.number,
          service_name: service.name,
          type: purchaseType,
          status: "active",
          time_remaining_ms: purchaseType === "rental" ? rentalDuration * 60 * 60 * 1000 : 20 * 60 * 1000,
          time_remaining_formatted: purchaseType === "rental" ? `${rentalDuration}h 0m` : "20m 0s",
          is_expired: false,
          sms_count: 0,
          expires_at: data.data.expires_at,
        })
        
        // Start polling
        const interval = setInterval(() => fetchSMS(data.data.number_id), 5000)
        setPollingInterval(interval)
        
        // Update URL
        router.push(`/dashboard/verification/${serviceId}?view=${data.data.number_id}`)
      } else {
        if (data.data?.shortfall) {
          toast.error(`Insufficient balance. You need ${formatCurrency(data.data.shortfall)} more.`)
        } else {
          toast.error(data.error || "Purchase failed")
        }
      }
    } catch (err) {
      toast.error("Failed to complete purchase")
    } finally {
      setIsPurchasing(false)
    }
  }

  const copyNumber = () => {
    if (activeNumber?.number) {
      navigator.clipboard.writeText(activeNumber.number)
      toast.success("Number copied to clipboard")
    }
  }

  const copySMS = (message: string) => {
    navigator.clipboard.writeText(message)
    toast.success("SMS copied to clipboard")
  }

  const handleCancel = async () => {
    if (!activeNumber) return
    
    try {
      const response = await fetch("/api/verification/cancel", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ numberId: activeNumber.id }),
      })
      
      const data = await response.json()
      
      if (data.success) {
        toast.success("Number cancelled")
        setActiveNumber(null)
        if (pollingInterval) clearInterval(pollingInterval)
        router.push(`/dashboard/verification/${serviceId}`)
      } else {
        toast.error(data.error || "Failed to cancel")
      }
    } catch (err) {
      toast.error("Failed to cancel number")
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    )
  }

  if (!service) {
    return (
      <div className="text-center py-12">
        <AlertCircle className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
        <p className="text-muted-foreground">Service not found</p>
        <Link href="/dashboard/verification">
          <Button className="mt-4">Back to Services</Button>
        </Link>
      </div>
    )
  }

  // View mode - showing active number
  if (activeNumber) {
    return (
      <div className="space-y-6">
        <Link href="/dashboard/verification">
          <Button variant="ghost" className="pl-0">
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Services
          </Button>
        </Link>

        <div>
          <h1 className="text-3xl font-bold tracking-tight">{service.name}</h1>
          <p className="text-muted-foreground mt-2">Your verification number</p>
        </div>

        {/* Number Card */}
        <Card className="border-2 border-[#006994]">
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <Phone className="h-5 w-5" />
                Your Number
              </CardTitle>
              <Badge variant={activeNumber.type === "rental" ? "default" : "secondary"}>
                {activeNumber.type === "rental" ? "Rental" : "One-time"}
              </Badge>
            </div>
          </CardHeader>
          <CardContent>
            <div className="flex items-center justify-between p-4 bg-muted rounded-lg">
              <span className="text-2xl font-mono font-bold">{activeNumber.number}</span>
              <Button variant="outline" size="sm" onClick={copyNumber}>
                <Copy className="h-4 w-4 mr-2" />
                Copy
              </Button>
            </div>
            
            <div className="mt-4 flex items-center gap-2 text-sm text-muted-foreground">
              <Clock className="h-4 w-4" />
              {activeNumber.is_expired ? (
                <span className="text-red-600 font-medium">Expired</span>
              ) : (
                <span>Expires in: <span className="font-mono font-medium text-orange-600">{activeNumber.time_remaining_formatted}</span></span>
              )}
            </div>
          </CardContent>
          {activeNumber.status === "active" && !activeNumber.is_expired && (
            <CardFooter>
              <Button variant="destructive" onClick={handleCancel} className="w-full">
                Cancel Number
              </Button>
            </CardFooter>
          )}
        </Card>

        {/* SMS Inbox */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <MessageSquare className="h-5 w-5" />
              SMS Inbox
              {smsList.length > 0 && (
                <Badge variant="secondary">{smsList.length}</Badge>
              )}
            </CardTitle>
            <CardDescription>
              SMS messages received on this number appear here automatically
            </CardDescription>
          </CardHeader>
          <CardContent>
            {smsList.length === 0 ? (
              <div className="text-center py-8">
                <MessageSquare className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                <p className="text-muted-foreground">No SMS received yet</p>
                <p className="text-sm text-muted-foreground mt-1">
                  Use the number above for verification. SMS will appear here within seconds.
                </p>
              </div>
            ) : (
              <div className="space-y-4">
                {smsList.map((sms) => (
                  <motion.div
                    key={sms.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="p-4 bg-muted rounded-lg"
                  >
                    <div className="flex items-start justify-between mb-2">
                      <div>
                        <p className="text-sm font-medium">From: {sms.from_number}</p>
                        <p className="text-xs text-muted-foreground">
                          {new Date(sms.received_at).toLocaleString()}
                        </p>
                      </div>
                      <Button variant="ghost" size="sm" onClick={() => copySMS(sms.message)}>
                        <Copy className="h-4 w-4" />
                      </Button>
                    </div>
                    <p className="font-mono text-sm whitespace-pre-wrap">{sms.message}</p>
                  </motion.div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Instructions */}
        <Card className="bg-muted/50">
          <CardContent className="p-6">
            <h4 className="font-medium mb-2">How to use this number</h4>
            <ol className="text-sm text-muted-foreground space-y-1 list-decimal list-inside">
              <li>Copy the number above</li>
              <li>Go to {service.name} and enter this number for verification</li>
              <li>Request the verification code on {service.name}</li>
              <li>Return here - the SMS will appear automatically</li>
              <li>Copy the verification code and complete your signup</li>
            </ol>
          </CardContent>
        </Card>
      </div>
    )
  }

  // Purchase mode
  return (
    <div className="space-y-6">
      <Link href="/dashboard/verification">
        <Button variant="ghost" className="pl-0">
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back to Services
        </Button>
      </Link>

      <div>
        <h1 className="text-3xl font-bold tracking-tight">{service.name}</h1>
        <p className="text-muted-foreground mt-2">{service.description}</p>
      </div>

      <div className="grid gap-6 lg:grid-cols-3">
        {/* Purchase Options */}
        <div className="lg:col-span-2 space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Select Purchase Type</CardTitle>
              <CardDescription>Choose the option that fits your needs</CardDescription>
            </CardHeader>
            <CardContent>
              <RadioGroup
                value={purchaseType}
                onValueChange={(v) => setPurchaseType(v as "onetime" | "rental")}
                className="grid gap-4"
              >
                <div>
                  <RadioGroupItem
                    value="onetime"
                    id="onetime"
                    className="peer sr-only"
                  />
                  <Label
                    htmlFor="onetime"
                    className="flex items-center justify-between p-4 border-2 rounded-lg cursor-pointer peer-data-[state=checked]:border-[#006994]"
                  >
                    <div className="flex items-center gap-3">
                      <Clock className="h-5 w-5 text-muted-foreground" />
                      <div>
                        <p className="font-medium">One-time Purchase</p>
                        <p className="text-sm text-muted-foreground">Valid for 20 minutes</p>
                      </div>
                    </div>
                    <span className="font-bold">{formatCurrency(service.onetime_price)}</span>
                  </Label>
                </div>

                <div>
                  <RadioGroupItem
                    value="rental"
                    id="rental"
                    className="peer sr-only"
                  />
                  <Label
                    htmlFor="rental"
                    className="flex items-center justify-between p-4 border-2 rounded-lg cursor-pointer peer-data-[state=checked]:border-[#006994]"
                  >
                    <div className="flex items-center gap-3">
                      <Calendar className="h-5 w-5 text-muted-foreground" />
                      <div>
                        <p className="font-medium">Rental</p>
                        <p className="text-sm text-muted-foreground">Valid for selected duration</p>
                      </div>
                    </div>
                    <span className="font-bold">From {formatCurrency(service.rental_price_per_day * 0.1)}</span>
                  </Label>
                </div>
              </RadioGroup>
            </CardContent>
          </Card>

          {purchaseType === "rental" && (
            <Card>
              <CardHeader>
                <CardTitle>Select Duration</CardTitle>
                <CardDescription>How long do you need the number?</CardDescription>
              </CardHeader>
              <CardContent>
                <RadioGroup
                  value={rentalDuration.toString()}
                  onValueChange={(v) => setRentalDuration(parseInt(v))}
                  className="grid grid-cols-2 sm:grid-cols-3 gap-3"
                >
                  {rentalDurations.map((duration) => (
                    <div key={duration.hours}>
                      <RadioGroupItem
                        value={duration.hours.toString()}
                        id={`duration-${duration.hours}`}
                        className="peer sr-only"
                      />
                      <Label
                        htmlFor={`duration-${duration.hours}`}
                        className="flex flex-col items-center p-3 border-2 rounded-lg cursor-pointer peer-data-[state=checked]:border-[#006994] peer-data-[state=checked]:bg-[#006994]/5"
                      >
                        <span className="font-medium">{duration.label}</span>
                        <span className="text-sm text-muted-foreground">
                          {formatCurrency(service.rental_price_per_day * duration.multiplier)}
                        </span>
                      </Label>
                    </div>
                  ))}
                </RadioGroup>
              </CardContent>
            </Card>
          )}
        </div>

        {/* Order Summary */}
        <div>
          <Card className="sticky top-6">
            <CardHeader>
              <CardTitle>Order Summary</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex justify-between">
                <span className="text-muted-foreground">Service</span>
                <span className="font-medium">{service.name}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">Type</span>
                <span className="font-medium capitalize">{purchaseType}</span>
              </div>
              {purchaseType === "rental" && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Duration</span>
                  <span className="font-medium">
                    {rentalDurations.find(d => d.hours === rentalDuration)?.label}
                  </span>
                </div>
              )}
              
              <Separator />
              
              <div className="flex justify-between items-center">
                <span className="text-muted-foreground">Total</span>
                <span className="text-2xl font-bold">{formatCurrency(calculatePrice())}</span>
              </div>

              {user && (
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Wallet Balance</span>
                  <span className={user.walletBalance < calculatePrice() ? "text-red-600" : "text-green-600"}>
                    {formatCurrency(user.walletBalance || 0)}
                  </span>
                </div>
              )}
            </CardContent>
            <CardFooter className="flex flex-col gap-3">
              <Button 
                className="w-full" 
                size="lg"
                onClick={handlePurchase}
                disabled={isPurchasing || (user?.walletBalance || 0) < calculatePrice()}
              >
                {isPurchasing ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Processing...
                  </>
                ) : (
                  <>
                    <CreditCard className="h-4 w-4 mr-2" />
                    Purchase with Wallet
                  </>
                )}
              </Button>
              
              {(user?.walletBalance || 0) < calculatePrice() && (
                <Link href="/dashboard/wallet" className="w-full">
                  <Button variant="outline" className="w-full">
                    Fund Wallet
                  </Button>
                </Link>
              )}
            </CardFooter>
          </Card>
        </div>
      </div>
    </div>
  )
}
